2	const FIRST_INSURANCE_SURCHARGE_RATE = 1 / 10;
3	const LOYALTY_DISCOUNT_RATE = 2 / 10;
4	const LOYALTY_YEARS_THRESHOLD = 2;
5	const FOLLOW_UP_DISCOUNT_RATE = 15 / 100;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
