16	const CURSED_SURCHARGE_RATE = 1 / 2;
17	
18	const COMPONENT_TYPES = ["rune", "moonstone"];
19	const BLOCK_SIZE = 3;
20	const BLOCK_PREMIUM = 60;
21	
22	const HIGHLY_ENCHANTED_THRESHOLD = 5;
23	const ENCHANTMENT_SURCHARGE_RATE = 3 / 10;
24	
25	type Item = { type: string; enchantment?: number; cursed?: boolean };
26	type Customer = { yearsAsCustomer: number };
27	
28	const isComponent = (item: Item): boolean =>
29	  COMPONENT_TYPES.includes(item.type);
30	
31	const isHighlyEnchanted = (item: Item): boolean =>
32	  (item.enchantment ?? 0) >= HIGHLY_ENCHANTED_THRESHOLD;
33	
34	const calculateItemBasePremium = (item: Item): number =>
35	  BASE_PREMIUMS[item.type] ?? 0;
36	
37	const calculateItemSurcharges = (item: Item): number => {
38	  const basePremium = calculateItemBasePremium(item);
39	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
40	  const enchantmentSurcharge = isHighlyEnchanted(item)
41	    ? basePremium * ENCHANTMENT_SURCHARGE_RATE
42	    : 0;
43	  return cursedSurcharge + enchantmentSurcharge;
44	};
45	
46	const countComponentsByType = (items: Item[]): Record<string, number> => {
47	  const counts: Record<string, number> = {};
48	  for (const item of items) {
49	    if (isComponent(item)) {
50	      counts[item.type] = (counts[item.type] ?? 0) + 1;
51	    }
52	  }
53	  return counts;
54	};
55	
56	const hasBlock = (componentCounts: Record<string, number>, type: string): boolean =>
57	  componentCounts[type] === BLOCK_SIZE;
58	
59	export const quote = (items: Item[], customer: Customer, contractNumber: number): number => {
60	  const componentCounts = countComponentsByType(items);
61	
62	  let policyBasePremium = 0;
63	  let itemSurcharges = 0;
64	
65	  for (const item of items) {
66	    if (isComponent(item) && hasBlock(componentCounts, item.type)) {
67	      continue;
68	    }
69	    policyBasePremium += calculateItemBasePremium(item);
70	    itemSurcharges += calculateItemSurcharges(item);
71	  }
72	
73	  for (const type of COMPONENT_TYPES) {
74	    if (hasBlock(componentCounts, type)) {
75	      policyBasePremium += BLOCK_PREMIUM;
76	    }
77	  }
78	
79	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
80	  const loyaltyDiscount =
81	    customer.yearsAsCustomer >= LOYALTY_YEARS_THRESHOLD
82	      ? policyBasePremium * LOYALTY_DISCOUNT_RATE
83	      : 0;
84	  const followUpDiscount =
85	    contractNumber > 1 ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
86	
87	  const totalPremium =
88	    policyBasePremium + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + itemSurcharges;
89	
90	  return Math.ceil(totalPremium) + PROCESSING_FEE;
91	};
92	
93	type Damage = { itemType: string; amount: number };
94	type ClaimResult = { payout: number; remainingCap: number };
95	
96	const INSURANCE_VALUES: Record<string, number> = {
97	  sword: 1000,
98	  amulet: 600,
99	  staff: 800,
100	  potion: 400,
101	  rune: 250,
102	  moonstone: 250,
103	};
104	
105	const DEDUCTIBLE = 100;
106	const CAP_MULTIPLIER = 2;
107	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
108	const CLAIM_HIGH_ENCHANTMENT_RATE = 1 / 2;
109	
110	const isHighlyEnchantedClaim = (item: Item): boolean =>
111	  (item.enchantment ?? 0) >= CLAIM_HIGH_ENCHANTMENT_THRESHOLD;
112	
113	const findPolicyItem = (policyItems: Item[], itemType: string): Item | undefined =>
114	  policyItems.find((item) => item.type === itemType);
115	
116	const calculateEffectiveDamage = (damage: Damage, policyItems: Item[]): number => {
117	  const matchedItem = findPolicyItem(policyItems, damage.itemType);
118	  if (matchedItem && isHighlyEnchantedClaim(matchedItem)) {
119	    return damage.amount * CLAIM_HIGH_ENCHANTMENT_RATE;
120	  }
121	  return damage.amount;
122	};
123	
124	export const claim = (
125	  policyItems: Item[],
126	  damages: Damage[],
127	  previousPayouts: number,
128	): ClaimResult => {
129	  const insuranceSum = policyItems.reduce(
130	    (sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0),
131	    0,
132	  );
133	  const cap = CAP_MULTIPLIER * insuranceSum;
134	  const availableCap = cap - previousPayouts;
135	
136	  let totalPayout = 0;
137	  for (const damage of damages) {
138	    const effectiveAmount = calculateEffectiveDamage(damage, policyItems);
139	    const payout = Math.max(0, effectiveAmount - DEDUCTIBLE);
140	    totalPayout += payout;
141	  }
142	
143	  totalPayout = Math.min(totalPayout, availableCap);
144	
145	  return { payout: totalPayout, remainingCap: availableCap - totalPayout };
146	};
